import { isNeedElement, isContainer } from './dom'


export const elementLevel = (element) => {
  if (element.children.length) {
    const childElement = element.children
    if ([].slice.call(childElement).some(element => element.children.length > 0)) {
      return false
    }
    return true
  }
  return true
};

const isSVG = (element) => {
  if (element.tagName.toLowerCase() === 'svg') {
    return true
  }
  let parent = element.parentElement
  let flag = false
  while (parent) {
    if (parent.tagName.toLowerCase() === 'svg') {
      parent = null
      flag = true
    } else {
      parent = parent.parentElement
    }
  }
  return flag
}

export function isTrack(node: Element, options: any): boolean {
  const windowHeight = window.innerHeight
  const windowWidth = window.innerWidth
  if (node.nodeType !== 1) {
    return false
  }
  if (!options.svg && isSVG(node)) {
    return false
  }
  if (['HTML', 'BODY'].includes(node.tagName.toUpperCase())) {
    return false
  }

  const element = node as HTMLElement
  if (element.style.display === 'none') {
    return false
  }
  if (isNeedElement(element, 'container', options.container_attr || '')) {
    return true
  }
  if (!isContainer(element, options) && !elementLevel(element) && !options.svg) {
    return false
  }
  // if (element.clientHeight * element.clientWidth > 0.5 * windowHeight * windowWidth) {
  //   return false
  // }
  return true
}
